var rootCmd = &cobra.Command{
    Use:   "photo",
    Short: "Manage personal digital photography archive",
}

func main() {
    if err := rootCmd.Execute(); err != nil {
        log.Fatal(err)
    }
}

func newArchivePath() (string, error) {
    home, err := os.UserHome()
    if err != nil {
        return "", err
    }
    return filepath.Join(home, ".photo"), nil
}

func initArchive(root string) error {
    if err := os.MkdirAll(root, 0755); err != nil {
        return err
    }
    photoDir := filepath.Join(root, "photos")
    if err := os.MkdirAll(photoDir, 0755); err != nil {
        return err
    }
    categoryDir := filepath.Join(photoDir, "categories")
    if err := os.MkdirAll(categoryDir, 0755); err != nil {
        return err
    }
    return nil
}

func newPhoto(entry struct {
    Date  string
    Category string
    Description string
}) error {
    photoDir, err := newArchivePath()
    if err != nil {
        return err
    }
    photoPath := filepath.Join(photoDir, fmt.Sprintf("%s.jpg", entry.Date))
    if err := ioutil.WriteFile(photoPath, []byte(entry.Description), 0644); err != nil {
        return err
    }
    categoryDir := filepath.Join(photoDir, entry.Category)
    if err := os.MkdirAll(categoryDir, 0755); err != nil {
        return err
    }
    return nil
}

func report(root string) {
    photoDir, err := newArchivePath()
    if err != nil {
        return
    }
    photos := make([]struct {
        Date  string
        Category string
        Description string
    }, 0)
    for _, entry := range os.ReadDir(photoDir) {
        if entry.IsDir() {
            continue
        }
        photoPath := filepath.Join(photoDir, entry.Name())
        file, err := os.Open(photoPath)
        if err != nil {
            continue
        }
        defer file.Close()
        description, err := ioutil.ReadAll(file)
        if err != nil {
            continue
        }
        date := filepath.Base(photoPath)
        photos = append(photos, struct {
            Date  string
            Category string
            Description string
        }{
            Date:  date,
            Category: filepath.Dir(filepath.Dir(photoPath)),
            Description: string(description),
        })
    }
    sort.Slice(photos, func(i, j int) bool {
        return photos[i].Date < photos[j].Date
    })
    for _, entry := range photos {
        fmt.Printf("Date: %s, Category: %s, Description: %s\n", entry.Date, entry.Category, entry.Description)
    }
}

var (
    rootCmd = &cobra.Command{
        Use:   "photo",
        Short: "Manage personal digital photography archive",
        PreRun: func(cmd *cobra.Command, args []string) {
            if err := initArchive(os.TempDir()); err != nil {
                fmt.Println(err)
                os.Exit(1)
            }
        },
    },
    initCmd = &cobra.Command{
        Use:   "init",
        Short: "Initialize a new archive",
        Run: func(cmd *cobra.Command, args []string) {
            fmt.Println("Archive initialized successfully")
        },
    },
    addCmd = &cobra.Command{
        Use:   "add",
