            date := cmd.Flags().StringP("date", "d", "", "Date of the photo")
            category := cmd.Flags().StringP("category", "c", "", "Category of the photo")
            description := cmd.Flags().StringP("description", "r", "", "Description of the photo")
            if date == "" || category == "" || description == "" {
                fmt.Println("Please provide all required fields")
                return
            }
            photo := struct {
                Date  string
                Category string
                Description string
            }{
                Date:  date,
                Category: category,
                Description: description,
            }
            if err := newPhoto(photo); err != nil {
                fmt.Println(err)
                return
            }
            fmt.Println("Photo added successfully")
        },
        Flags: func(cmd *cobra.Command) {
            dateFlag := cmd.Flags().StringP("date", "d", "", "Date of the photo")
            categoryFlag := cmd.Flags().StringP("category", "c", "", "Category of the photo")
            descriptionFlag := cmd.Flags().StringP("description", "r", "", "Description of the photo")
            cmd.Flags().RequiredRangeFlags("date", "category", "description")
        },
    },
    reportCmd = &cobra.Command{
        Use:   "report",
        Short: "Generate a summary report of all photos by category",
        Run: func(cmd *cobra.Command, args []string) {
            report(os.TempDir())
        },
    },
)

func init() {
    rootCmd.AddCommand(initCmd)
    rootCmd.AddCommand(addCmd)
    rootCmd.AddCommand(reportCmd)
    cobra.OnInitialize(func() {
