    if (error.code === 'ENOENT') {
      console.error(`Error: File not found - ${error.message}`);
    } else if (error.code === 'EACCES') {
      console.error(`Error: Permission denied - ${error.message}`);
    } else {
      console.error(`Error: An error occurred - ${error.message}`);
    }
  }
