use std::fs::File;
use std::io::{Read, Write, BufReader, BufWriter};
use futures::{Future, stream::FusedStream, prelude::*};
use serde_json::Value;

#[derive(Debug)]
struct ReadFuture {
    path: String,
}

impl ReadFuture {
    fn new(path: String) -> Self {
        ReadFuture { path }
    }
}

impl Stream for ReadFuture {
    type Item = Result<Vec<u8>, std::io::Error>;

    fn poll_next(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
        let mut file = File::open(&self.path).map_err(|e| {
            eprintln!("Error opening file {}: {}", self.path, e);
            std::io::Error::new(std::io::ErrorKind::NotFound, "File not found")
        })?;
        let mut content = Vec::new();
        file.read_to_end(&mut content).map_err(|e| {
            eprintln!("Error reading file {}: {}", self.path, e);
            std::io::Error::new(std::io::ErrorKind::ReadOnly, "File not readable")
        })?;
        Ok(Some((Ok(content), cx.waker())))
    }
}

#[derive(Debug)]
struct ConcatFuture {
    contents: Box<dyn FusedStream<Item = Result<Vec<u8>, std::io::Error>>>,
}

impl ConcatFuture {
    fn new(contents: Box<dyn FusedStream<Item = Result<Vec<u8>, std::io::Error>>>>) -> Self {
        ConcatFuture { contents }
    }
}

impl Stream for ConcatFuture {
    type Item = Result<Vec<u8>, std::io::Error>;

    fn poll_next(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
        let mut contents = vec![];
        self.contents.poll_next_unpin(cx).map(|r| {
            match r {
                Ok(Ok(content)) => contents.extend(content),
                Ok(Err(e)) => {
                    eprintln!("Error reading file: {}", e);
                    return Err(e);
                }
                Err(_) => return Err(std::io::Error::new(std::io::ErrorKind::Other, "Stream ended")),
            }
        });
        if contents.is_empty() {
            return Ok(None);
        }
        Ok(Some((Ok(contents), cx.waker())))
    }
}

#[tokio::main]
async fn main() {
    let input_file = "input.json";
    let output_file = "output.txt";

    let file_paths: Vec<String> = {
        let file_paths: Vec<Value> = serde_json::from_reader(File::open(input_file).unwrap()).unwrap();
        file_paths.into_iter().map(|path| path.as_str().unwrap().to_string()).collect()
    };

    let read_futures = file_paths.into_iter().map(|path| ReadFuture::new(path)).collect::<Vec<_>>();
    let read_future = ReadFuture::new("input.txt").into_future();
    let read_futures = read_futures.into_future().zip(read_future);

    let contents = read_futures.for_each(|(path, future)| future.map(|content| (path, content))).flatten().map(|(path, content)| (path, content));

    let concat_future = ConcatFuture::new(contents);
    let concatenated_content = concat_future.into_future();

    let output_file = File::create(output_file).unwrap();
    let mut writer = BufWriter::new(output_file);

    concatenated_content.await.unwrap().unwrap().into_writer(writer).unwrap();
}
