use tide::{App, Request, Response, StatusCode, StatusMessage};
use serde::{Deserialize, Serialize};
use serde_json;

struct ProductCode {
    code: String,
}

#[derive(Deserialize, Serialize)]
struct RequestBody {
    product_codes: Vec<ProductCode>,
}

fn main() {
    let mut app = App::new();

    let valid_codes = vec!["ABC123".to_string(), "XYZ789".to_string()];

    app.at("/validate-product-codes").post(move |req: Request<Body>| {
        let body = req.body::<RequestBody>().expect("Invalid JSON body");
        let mut valid = vec![];
        let mut invalid = vec![];

        for code in body.product_codes {
            if valid_codes.contains(&code.code) {
                valid.push(code.code.clone());
            } else {
                invalid.push(code.code.clone());
            }
        }

        let json = serde_json::json!({
            "valid_codes": valid,
            "invalid_codes": invalid,
        });

        Ok(Response::new(json).status(StatusCode::OK))
    });

    app.listen("127.0.0.1:8080").expect("Failed to start server");
}
