    let data: serde_json::Value = serde_json::from_str(&data).unwrap();

    let employees: Vec<Employee> = data
        .as_array()
        .unwrap()
        .into_iter()
        .map(|item| {
            let employee: serde_json::Value = item.as_object().unwrap().clone();
            Employee {
                id: employee["id"].as_u64().unwrap() as i32,
                name: employee["name"].as_str().unwrap().to_string(),
                age: employee["age"].as_u64().unwrap() as i32,
            }
        })
        .collect();

    let make_service = make_service_fn(|_conn| async { Ok::<_, hyper::Error>(service_fn(move |req| async { handle_request(req, &employees) })) });

    let client = Client::builder().build::<_, hyper::Body>(HttpConnector::new());
    let uri = Uri::from_static("http://localhost:8000/employees");
    client.get(uri).body(Body::from("")).await.unwrap();

    let addr = ([127, 0, 0, 1], 8000).into();
    hyper::server::run(
        addr,
        move |conn| {
            let service = make_service(conn);
            let handle = service.await.unwrap();
            handle
        },
        make_service,
    )
    .await
    .unwrap();
}

async fn handle_request(req: Request<Body>, employees: &Vec<Employee>) -> hyper::Response<Body> {
    let path = req.uri().path();
    if path == "/employees" {
        let json = json!({
            "employees": employees,
        });
        Ok(hyper::Response::new(Body::from(json.to_string())))
    } else {
        let json = json!({
            "error": "Invalid request",
        });
        Ok(hyper::Response::new(Body::from(json.to_string())))
    }
}
