use tokio::io::{AsyncRead, AsyncWrite};
use tokio::net::TcpListener;
use serde_json;
use serde_json::Value;

async fn handle_request(mut stream: TcpStream) -> Result<(), Box<dyn Error>> {
    let mut buffer = String::new();
    stream.read_to_string(&mut buffer).await?;

    let data: Value = match serde_json::from_str(&buffer) {
        Ok(data) => data,
        Err(_) => return Err("Invalid JSON format".into()),
    };

    let list: Vec<i32> = match data.get("list").and_then(|list| list.as_array()) {
        Some(list) => list
            .iter()
            .map(|x| x.as_i64().unwrap())
            .collect(),
        None => return Err("Missing list in JSON".into()),
    };

    let sorted_list = list.into_iter().collect::<VecDeque<_>>().sort();
    let sorted_list = sorted_list.into_iter().collect::<Vec<_>>();

    let response = format!("{{\"sorted_list\": {}}}", serde_json::to_string(&sorted_list)?);
    stream.write(response.as_bytes()).await?;

    Ok(())
}

#[tokio::main]
async fn main() {
