    println!("Server listening on port 8080");

    loop {
        match listener.accept().await {
            Ok((mut stream, _) ) => {
                thread::spawn(move || {
                    if let Err(e) = handle_request(stream).await {
                        eprintln!("Error: {}", e);
                    }
                });
            }
            Err(e) => eprintln!("Error: {}", e),
        }
    }
