use std::net::TcpListener;
use std::io::{Read, Write};
use tokio_tungstenite::{connect_async, tungstenite::protocol::Message};
use tokio::{sync::mpsc, task};

#[tokio::main]
async fn main() {
    let listener = TcpListener::bind("127.0.0.1:8080").expect("Failed to bind");

    let (tx, mut rx) = mpsc::channel(5);

    for stream in listener.incoming() {
        let (mut stream, _) = stream.expect("Failed to accept");

        task::spawn(async move {
            let (mut write_stream, _) = connect_async(stream).await.expect("Failed to connect");

            loop {
                let mut buffer = [0; 1024];
                match write_stream.read(&mut buffer).await {
                    Ok(n) => {
                        if n == 0 {
                            break;
                        }

                        match Message::from_slice(&buffer[..n]) {
                            Ok(msg) => {
                                match msg {
                                    Message::Text(text) => {
                                        if text == "END" {
                                            write_stream.close().await.expect("Failed to close");
                                            break;
                                        }

                                        write_stream.send(Message::Text(text)).await.expect("Failed to send");
                                    }
                                    _ => {}
                                }
                            }
                            Err(e) => {
                                eprintln!("Error parsing message: {}", e);
                            }
                        }
                    }
                    Err(e) => {
                        eprintln!("Error reading from stream: {}", e);
                    }
                }
            }
        });
    }

    tokio::select! {
        _ = rx.recv() => {
            println!("Server shutting down");
        }
        _ = listener.incoming() => {}
    }
}
