use rocket::{get, request::FromRequest, serde::Deserialize};
use rocket::fairing::AdHoc;
use rocket::http::Status;
use rocket::request::FromRequest;
use rocket::serde::urlencoded::FromUrlEncoded;

#[derive(Debug, Deserialize)]
struct GreetingRequest {
    name: Option<String>,
}

impl<'a> FromUrlEncoded<'a> for GreetingRequest {
    type Error = String;

    fn from_url_encoded(data: &'a [(&'a str, &'a str)]) -> Result<Self, Self::Error> {
        let mut name = None;
        for (key, value) in data {
            if key == "name" {
                name = Some(value.to_string());
            }
        }
        Ok(GreetingRequest { name })
    }
}

struct GreetingRequestParser;

impl<'a> FromRequest<'a> for GreetingRequestParser {
    type Error = String;

    fn from_request(request: &'a rocket::request::Request<'_>) -> rocket::request::Outcome<Self::Error, GreetingRequest> {
        let mut greeting_request = GreetingRequest { name: None };
        if let Some(url_encoded) = request.match_info().get_one::<String>("name") {
            greeting_request.name = Some(url_encoded);
        }
        Ok(rocket::request::Outcome::Success(greeting_request))
    }
}

#[get("/greeting?<name>")]
fn greeting(name: Option<String>) -> Result<rocket::response::Response, rocket::error::Error> {
    match name {
        Some(n) => Ok(rocket::response::response().header("Content-Type", "text/plain").body(format!("Hello, {}!", n))),
        None => Ok(rocket::response::response().header("Content-Type", "text/plain").body("Hello, Guest!")),
    }
}

fn main() {
    let routes = rocket::routes![
        rocket::routes::get("/greeting?<name>").to(greeting),
    ];

    rocket::ignite()
        .attach(GreetingRequestParser::new())
        .attach(AdHoc::on_error(|err| rocket::response::response().status(Status::InternalServerError).body(err.to_string())))
        .mount("/", routes)
        .launch();
}
