        return io-ts Result.fail('Invalid publishedDate');
      }
      return io-ts Result.success<BlogPost>({
        id,
        title,
        content,
        publishedDate,
      });
    } catch (error) {
      return io-ts Result.fail('Error decoding blog post');
    }
