// Import required libraries
const express = require('express');
const app = express();
const server = require('http').createServer(app);
const io = require('socket.io')(server);
const moment = require('moment');

// Store chat rooms and their participants
const chatRooms = {};

// Store all users and their rooms
const users = {};

// Set up socket.io event listeners
io.on('connection', (socket) => {
  console.log('New user connected');

  // Handle user joining a room
  socket.on('joinRoom', (roomName) => {
    if (!chatRooms[roomName]) {
      chatRooms[roomName] = [];
      io.to(roomName).emit('newRoomCreated');
    }

    if (!users[socket.id]) {
      users[socket.id] = { name: '', room: '', messages: [] };
    }

    users[socket.id].name = socket.handshake.query.name;
    users[socket.id].room = roomName;
    chatRooms[roomName].push(users[socket.id]);

    io.to(roomName).emit('userJoined', users[socket.id]);
    io.to(roomName).emit('messages', chatRooms[roomName]);
  });

  // Handle user sending a message
  socket.on('sendMessage', (roomName, message) => {
    if (chatRooms[roomName]) {
      chatRooms[roomName].forEach((user) => {
        if (user.name === users[socket.id].name) {
          return;
        }

        io.to(roomName).emit('newMessage', {
          name: users[socket.id].name,
          message,
          timestamp: moment().format('YYYY-MM-DD HH:mm:ss'),
        });
      });
    }
  });

  // Handle user disconnection
  socket.on('disconnect', () => {
    console.log('User disconnected');

    if (users[socket.id]) {
      const room = users[socket.id].room;
      const index = chatRooms[room].indexOf(users[socket.id]);

      if (index !== -1) {
        chatRooms[room].splice(index, 1);
        io.to(room).emit('userLeft', users[socket.id]);
        io.to(room).emit('messages', chatRooms[room]);
      }

      delete users[socket.id];
    }
  });
});

// Set up server port
const port = 3000;

// Start server
server.listen(port, () => {
  console.log(`Server started on port ${port}`);
});
