package main

import (
    "encoding/json"
    "log"
    "net/http"
    "strconv"

    "github.com/gorilla/mux"
)

type Product struct {
    ID       string `json:"id"`
    Name     string `json:"name"`
    Price    float64 `json:"price"`
}

var products = []Product{
    {ID: "1", Name: "Product 1", Price: 10.99},
    {ID: "2", Name: "Product 2", Price: 9.99},
}

func getHandler(w http.ResponseWriter, r *http.Request) {
    params := mux.Vars(r)
    id := params["id"]

    for _, product := range products {
        if product.ID == id {
            json.NewEncoder(w).Encode(product)
            return
        }
    }

    json.NewEncoder(w).Encode(http.StatusNotFound)
}

func postHandler(w http.ResponseWriter, r *http.Request) {
    var newProduct Product
    err := json.NewDecoder(r.Body).Decode(&newProduct)
    if err != nil {
        http.Error(w, err.Error(), http.StatusBadRequest)
        return
    }

    products = append(products, newProduct)
    json.NewEncoder(w).Encode(newProduct)
}

func putHandler(w http.ResponseWriter, r *http.Request) {
    params := mux.Vars(r)
    id := params["id"]

    for index, product := range products {
        if product.ID == id {
            var updatedProduct Product
            err := json.NewDecoder(r.Body).Decode(&updatedProduct)
            if err != nil {
                http.Error(w, err.Error(), http.StatusBadRequest)
                return
            }

            products[index] = updatedProduct
            json.NewEncoder(w).Encode(updatedProduct)
            return
        }
    }

    json.NewEncoder(w).Encode(http.StatusNotFound)
}

func deleteHandler(w http.ResponseWriter, r *http.Request) {
    params := mux.Vars(r)
    id := params["id"]

    for index, product := range products {
        if product.ID == id {
            products = append(products[:index], products[index+1:]...)
            json.NewEncoder(w).Encode(http.StatusNoContent)
            return
        }
    }

    json.NewEncoder(w).Encode(http.StatusNotFound)
}

func main() {
    router := mux.NewRouter()

    router.HandleFunc("/products/{id}", getHandler).Methods("GET")
    router.HandleFunc("/products", postHandler).Methods("POST")
    router.HandleFunc("/products/{id}", putHandler).Methods("PUT")
    router.HandleFunc("/products/{id}", deleteHandler).Methods("DELETE")

    log.Fatal(http.ListenAndServe(":8000", router))
}
