        prices.push((id, price));
    }

    for (id, price) in prices {
        let url = format!("https://api.coingecko.com/api/v3/coins/{id}");
        let response = reqwest::get(url).await?;
        let response_data: CoinGeckoResponse = response.json().await?;

        let coin = response_data.coins.iter().find(|c| c.id == id).unwrap();
        println!("{}: ${}", coin.name, price);
    }

    Ok(())
}

