async function registerUser(data: { username: string; email: string; password: string }) {
  try {
    const result = await userSchema.parse(data);
    return result;
  } catch (error) {
    const errors: { [key: string]: string } = {};
    for (const message of error.issues) {
      if (message.path) {
        if (message.path.name === 'username') {
          errors.username = message.message;
        } else if (message.path.name === 'email') {
          errors.email = message.message;
        } else if (message.path.name === 'password') {
          errors.password = message.message;
        }
      } else {
        errors[message.path] = message.message;
      }
    }
    return errors;
  }
}

