package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"os"
	"path/filepath"
	"sort"
	"time"

	"github.com/urfave/cli"
)

type Record struct {
	Name  string `json:"name"`
	Timestamp time.Time `json:"timestamp"`
}

func main() {
	app := cli.NewApp()
	app.Name = "jsonProcessor"
	app.Version = "1.0"
	app.Author = "Your Name"
	app.Description = "A command-line tool to process JSON files in a directory."
	app.UseFlagger("json files must be in JSON format")
	app.UseFlagger("missing directory or file error")
	app.UseFlagger("parse error")
	app.CommandLineFlags = []cli.Flag{
		&cli.StringFlag{
			Name:   "directory",
			Usage:  "directory path to read JSON files",
			Required: true,
		},
		&cli.StringFlag{
			Name:   "time-filter",
			Usage:  "optional time filter in YYYY-MM-DD format",
			Required: false,
		},
	}

	err := app.Run(os.Args)
	if err != nil {
		log.Fatal(err)
	}
}

func readJSONFiles(dir string) ([]Record, error) {
	files, err := ioutil.ReadDir(dir)
	if err != nil {
		return nil, err
	}

	var records []Record
	for _, file := range files {
		if file.IsDir() {
			continue
		}
		if filepath.Ext(file.Name()) != ".json" {
			continue
		}
		data, err := ioutil.ReadFile(filepath.Join(dir, file.Name()))
		if err != nil {
			return nil, err
		}
		var records2 []Record
		err = json.Unmarshal(data, &records2)
		if err != nil {
			return nil, err
		}
		records = append(records, records2...)
	}
	return records, nil
}

func filterRecords(records []Record, timeFilter string) ([]Record, error) {
	if timeFilter != "" {
		t, err := time.Parse("2006-01-02", timeFilter)
		if err != nil {
			return nil, err
		}
		return filter(records, t)
	}
	return records, nil
}

func filter(records []Record, t time.Time) ([]Record, error) {
	var filteredRecords []Record
	for _, record := range records {
		if record.Timestamp.After(t) || record.Timestamp.Before(t) {
			continue
		}
		filteredRecords = append(filteredRecords, record)
	}
	return filteredRecords, nil
}

func aggregateNames(records []Record) []string {
	names := make(map[string]bool)
	for _, record := range records {
		names[record.Name] = true
	}
	var sortedNames []string
	for name := range names {
		sortedNames = append(sortedNames, name)
	}
	sort.Strings(sortedNames)
	return sortedNames
}

func printNames(names []string) {
	for _, name := range names {
		fmt.Println(name)
	}
}
