use std::fs::File;
use std::io::{BufReader, BufRead};
use std::path::Path;

#[derive(Deserialize, Serialize)]
struct Student {
    name: String,
    age: i32,
    gpa: f64,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Read JSON file
    let file = File::open("students.json")?;
    let reader = BufReader::new(file);

    // Deserialize JSON into a list of Student structs
    let mut students: Vec<Student> = reader
        .lines()
        .map(|line| {
            let student: Student = serde_json::from_str(&line.unwrap())?;
            Ok(student)
        })
        .collect::<Result<Vec<_>, _>>()?;

    // Calculate average GPA
    let average_gpa = students.iter().map(|student| student.gpa).sum::<f64>() / students.len() as f64;

    // Serialize average GPA back into a JSON file
    let file = File::create("average_gpa.json")?;
    let mut writer = serde_json::Writer::new(file);
    writer.write_all(serde_json::to_string(&average_gpa).as_bytes())?;

    Ok(())
}
