use sqlx::{Pool,PgPool};
use sqlx::postgres::PgConnection;
use sqlx::types::PasswordHash;
use sqlx::PgResult;
use sqlx::PgError;
use bcrypt::{hash, verify};
use serde::{Serialize, Deserialize};
use uuid::Uuid;

#[derive(Serialize, Deserialize, Debug, Clone)]
struct User {
    id: Uuid,
    username: String,
    password: String,
}

async fn register_user(pool: &Pool<PgConnection>) -> Result<User, PgError> {
    let username = get_input("Enter a username: ").await?;
    let password = get_input("Enter a password: ").await?;
    let hashed_password = hash(password, bcrypt::config::DEFAULT).unwrap();

    let result = sqlx::query_as!(
        User,
        r#"
            INSERT INTO users (id, username, password)
            VALUES ($1, $2, $3)
            RETURNING *
        "#,
        Uuid::new_v4(),
        username,
        PasswordHash::new(hashed_password)
    )
    .fetch_one(pool)
    .await?;

    Ok(result)
}

async fn login_user(pool: &Pool<PgConnection>) -> Result<User, PgError> {
    let username = get_input("Enter your username: ").await?;
    let password = get_input("Enter your password: ").await?;

    let result = sqlx::query_as!(
        User,
        r#"
            SELECT id, username, password
            FROM users
            WHERE username = $1
        "#,
        username
    )
    .fetch_one(pool)
    .await?;

    if let Some(user) = result {
        if verify(&password, &user.password).is_ok() {
            Ok(user)
        } else {
            Err(PgError::from_sqlite("Invalid password"))
        }
    } else {
        Err(PgError::from_sqlite("User not found"))
    }
}

async fn main() -> Result<(), PgError> {
    let pool = PgPool::connect("postgres://localhost:5432/mydb", PoolOptions::default())
        .await?;

    loop {
        println!("1. Register user");
        println!("2. Login user");
        println!("3. Exit");

        let input = get_input("Choose an option: ").await?;
        match input {
            1 => {
                let user = register_user(&pool).await?;
                println!("User registered successfully!");
            }
            2 => {
                let user = login_user(&pool).await?;
                println!("User logged in successfully!");
            }
            3 => {
                break;
            }
            _ => {
                println!("Invalid option");
            }
        }
    }

    Ok(())
}

async fn get_input(prompt: &str) -> Result<String, PgError> {
    println!("{}", prompt);
    let mut input = String::new();
    std::io::stdin().read_line(&mut input).await?;

    Ok(input.trim().to_string())
}
