package main

import (
    "encoding/json"
    "fmt"
    "log"
    "os"
    "time"

    "github.com/ovh/protector/actor"
    "github.com/ovh/protector/actor/cluster"
    "github.com/ovh/protector/actor/cluster/cluster"
    "github.com/ovh/protector/actor/cluster/cluster/cluster"
    "github.com/ovh/protector/actor/cluster/cluster/cluster"
)

// TradingData represents the trading data to be processed
type TradingData struct {
    Date     string `json:"date"`
    Open      float64 `json:"open"`
    High      float64 `json:"high"`
    Low       float64 `json:"low"`
    Close     float64 `json:"close"`
    Volume    int     `json:"volume"`
}

// TradingActor represents an actor responsible for processing trading data
type TradingActor struct {
    actor.Actor
    cluster.Cluster
    volume map[string]int
}

// NewTradingActor returns a new instance of TradingActor
func NewTradingActor(id string) (*TradingActor, error) {
    actor, err := actor.NewActor(id)
    if err != nil {
        return nil, err
    }

    cluster, err := cluster.NewCluster(actor)
    if err != nil {
        return nil, err
    }

    return &TradingActor{actor: actor, cluster: cluster}, nil
}

// ProcessTradingData processes the trading data and dispatches a message to the cluster
func (t *TradingActor) ProcessTradingData(data TradingData) {
    t.volume[data.Date] += data.Volume
    msg := cluster.Message{Data: data}
    t.cluster.Dispatch(msg)
}

// GetTradingVolume returns the overall trading volume
func (t *TradingActor) GetTradingVolume() int {
    return t.volume[""]
}

// GetHighestStockPrice returns the highest stock price traded during the session
func (t *TradingActor) GetHighestStockPrice() float64 {
    var highestPrice float64
    for _, data := range t.volume {
        if data > highestPrice {
            highestPrice = data
        }
    }
    return highestPrice
}

func main() {
    // Read trading data from CSV file
    file, err := os.Open("trading_data.csv")
    if err != nil {
        log.Fatal(err)
    }
    defer file.Close()

    var tradingData TradingData
    scanner := csv.NewScanner(file)
    scanner.Scan()
    if err := scanner.Err(); err != nil {
        log.Fatal(err)
    }
    for scanner.Scan() {
        var data TradingData
        err = json.Unmarshal(scanner.Bytes(), &data)
        if err != nil {
            log.Fatal(err)
        }
        // Process trading data
        actor, err := NewTradingActor("trader")
        if err != nil {
            log.Fatal(err)
        }
        actor.ProcessTradingData(data)
    }

    // Aggregate responses from the cluster
    cluster, err := cluster.NewCluster(cluster.ClusterConfig{})
    if err != nil {
        log.Fatal(err)
    }
    cluster.Start()

    // Wait for the cluster to finish
    cluster.Wait()

    // Get overall trading volume and highest stock price
    volume := cluster.GetTradingVolume()
    highestPrice := cluster.GetHighestStockPrice()

    fmt.Printf("Overall trading volume: %d\n", volume)
    fmt.Printf("Highest stock price traded during the session: %.2f\n", highestPrice)
}
