import { Container, InjectionError } from 'typedi';
import { LoggerService } from './LoggerService';
import { UserService } from './UserService';

class LoggerService {
  log(message: string): void {
    console.log(message);
  }
}

class UserService {
  private logger: LoggerService;

  constructor(logger: LoggerService) {
    this.logger = logger;
  }

  public logMessage(message: string): void {
    this.logger.log(message);
  }
}

async function main() {
  try {
    const container = new Container();
    container.bind(LoggerService).toSelf();

    const logger = container.get(LoggerService);
    const userService = new UserService(logger as LoggerService);

    userService.logMessage('Hello, world!');
  } catch (error) {
    if (error instanceof InjectionError) {
      console.error('Error resolving dependencies:', error);
    } else {
      console.error('Unexpected error:', error);
    }
  }
}

main();
