import axios from 'axios';
import { match, matchAll, some } from 'ts-pattern';

interface Character {
  name: string;
  gender: string;
  species: string;
}

interface CharacterList {
  results: Character[];
}

interface Error {
  error: string;
}

const apiEndpoint = 'https://swapi.dev/api/people/';

async function fetchCharacters(): Promise<void> {
  try {
    const response = await axios.get(apiEndpoint);
    const characters = response.data;

    if (match(characters, {
      results: matchAll(Character),
      error: match(Error, (error) => error.error),
    })) {
      for (const character of characters.results) {
        const formattedCharacter = {
          name: character.name,
          gender: character.gender,
          species: character.species,
        };

        console.log(formattedCharacter);
      }
    } else {
      console.error('Failed to parse response:', characters);
    }
  } catch (error) {
    console.error('Error fetching characters:', error);
  }
}

fetchCharacters();
