package main

import (
    "fmt"
    "sync"
)

func sumConcurrently(nums []int) int {
    var wg sync.WaitGroup
    var total int

    // Create a channel to receive results
    results := make(chan int)

    // Start a goroutine for each number
    for _, num := range nums {
        wg.Add(1)
        go func(n int) {
            defer wg.Done()
            total += n
            results <- total
        }(num)
    }

    // Close the channel after all numbers have been processed
    go func() {
        wg.Wait()
        close(results)
    }()

    // Receive results from the channel
    for res := range results {
        total = res
    }

    return total
}

func main() {
    nums := []int{1, 2, 3, 4, 5}
    fmt.Println(sumConcurrently(nums))
}
