import requests
import json
import sys
import logging
import time

class WeatherClient:
    def __init__(self, api_endpoint):
        self.api_endpoint = api_endpoint
        self.logger = self.configure_logging()

    def configure_logging(self):
        logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
        return logging.getLogger()

    def get_weather_data(self):
        try:
            response = requests.get(self.api_endpoint)
            response.raise_for_status()
        except requests.exceptions.RequestException as e:
            self.logger.error(f"Request Exception: {e}")
            return None

        try:
            weather_data = response.json()
        except json.JSONDecodeError as e:
            self.logger.error(f"JSON Decode Error: {e}")
            return None

        if 'main' in weather_data and 'temp' in weather_data['main'] and 'humidity' in weather_data['main'] and 'weather' in weather_data:
            temperature = weather_data['main']['temp']
            humidity = weather_data['main']['humidity']
            weather_conditions = weather_data['weather'][0]['description']
            return {
                'Temperature': f"{temperature}°C",
                'Humidity': f"{humidity}%",
                'Weather Conditions': weather_conditions
            }
        else:
            return None

    def get_current_version(self):
        return sys.version_info

    def run(self):
        while True:
            try:
                weather_data = self.get_weather_data()
                if weather_data:
                    print("\nCurrent Weather Data:")
                    for key, value in weather_data.items():
                        print(f"{key}: {value}")
                else:
                    print("\nFailed to retrieve weather data.")
                time.sleep(60)  # Wait for 1 minute
            except Exception as e:
                self.logger.error(f"Exception: {e}")
                time.sleep(60)  # Wait for 1 minute


if __name__ == "__main__":
    api_endpoint = input("Enter the API endpoint: ")
    client = WeatherClient(api_endpoint)
    current_version = client.get_current_version()
    print(f"\nCurrent Python Version: {current_version.major}.{current_version.minor}.{current_version.micro}")
    client.run()
